import { useCallback } from 'react';
import { trackView, trackClick } from '../../services/adService';
import useIntersectionObserver from '../../hooks/useIntersectionObserver';

const AdCard = ({ ad }) => {
  const handleVisible = useCallback(() => {
    trackView(ad._id).catch(() => {});
  }, [ad._id]);

  const ref = useIntersectionObserver(handleVisible, { threshold: 0.5 });

  const handleClick = () => {
    trackClick(ad._id).catch(() => {});
    window.open(ad.targetLink, '_blank', 'noopener,noreferrer');
  };

  return (
    <div ref={ref} style={styles.card} onClick={handleClick} role="button" tabIndex={0}
      onKeyDown={(e) => e.key === 'Enter' && handleClick()}
      aria-label={`Sponsored: ${ad.title}`}>
      <span style={styles.label}>Sponsored</span>
      {ad.imageUrl && <img src={ad.imageUrl} alt={ad.title} style={styles.image} />}
      <div style={styles.body}>
        <p style={styles.title}>{ad.title}</p>
      </div>
    </div>
  );
};

const styles = {
  card: { background: '#fffbea', border: '1px solid #f0d060', borderRadius: 8, marginBottom: 16, overflow: 'hidden', cursor: 'pointer' },
  label: { display: 'block', fontSize: 10, color: '#999', padding: '4px 12px', textTransform: 'uppercase', letterSpacing: 1 },
  image: { width: '100%', height: 160, objectFit: 'cover' },
  body: { padding: '8px 12px 12px' },
  title: { fontWeight: 600, fontSize: 14, color: '#333', margin: 0 },
};

export default AdCard;
